mapper.select:
select id, tenant_id, file_id, pipeline_instance_id, channel_code, dispatch_target, dispatch_status, dispatch_attempt, receipt_code, receipt_status, external_request_id, error_code, error_message, dispatched_at, ack_at, created_at, updated_at from batch.file_dispatch_record where tenant_id = #{tenantId}
and file_id = #{fileId}
and channel_code = #{channelCode}
and dispatch_status = #{dispatchStatus}
and receipt_status = #{receiptStatus}
and created_at >= #{fromTime}
and created_at <= #{toTime}
order by id desc
limit #{pageRequest.pageSize} offset (#{pageRequest.pageNo} - 1) * #{pageRequest.pageSize}

select count(1)
from batch.file_dispatch_record
where tenant_id = #{tenantId}

    and file_id = #{fileId}


    and channel_code = #{channelCode}


    and dispatch_status = #{dispatchStatus}


    and receipt_status = #{receiptStatus}


    and created_at >= #{fromTime}


    and created_at <= #{toTime}
